module counter12bit_up_sync_clr (
    input clk,
    input clr,
    input en,
    output [11:0] q
);

    reg [11:0] count_reg;

    always @(posedge clk) begin
        if (clr)
            count_reg <= 12'b0;
        else if (en)
            count_reg <= count_reg + 1;
    end

    assign q = count_reg;

endmodule
